def factorial(n):
    if n < 0:
        raise ValueError('Negative numbers not allowed')
    if n in (0, 1):
        return 1
    return n * factorial(n - 1)

def fibonacci(n):
    if n < 0:
        raise ValueError('Negative numbers not allowed')
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

